import { WorkerEntrypoint } from "cloudflare:workers";

export interface TurnContext {
  turn: number;
  input: string;
}

export interface ToolDefinition {
  name: string;
  run: (args: string) => unknown | Promise<unknown>;
}

export type TurnHook = (ctx: TurnContext) => unknown | Promise<unknown>;

/** The API a plugin uses to expose tools and lifecycle hooks. */
export interface PluginHostApi {
  addTool(tool: ToolDefinition): void;
  onBeforeTurnStart(hook: TurnHook): void;
  onBeforeTurnEnd(hook: TurnHook): void;
}

/** What a plugin's `register()` hands back to the framework. */
export interface PluginManifest {
  tools: ToolDefinition[];
  beforeTurnStart: TurnHook[];
  beforeTurnEnd: TurnHook[];
}

export type PluginSetup = (host: PluginHostApi) => void;

/**
 * Helper a plugin author uses to declare a plugin. Returns a WorkerEntrypoint
 * whose `register()` builds the manifest by running `setup` against a local
 * host builder (inside the plugin's own isolate), then returns it to the
 * framework over RPC — the tool/hook callbacks travel back as RPC stubs.
 */
export function definePlugin(setup: PluginSetup) {
  return class PluginEntrypoint extends WorkerEntrypoint {
    register(): PluginManifest {
      const tools: ToolDefinition[] = [];
      const beforeTurnStart: TurnHook[] = [];
      const beforeTurnEnd: TurnHook[] = [];
      setup({
        addTool: (tool) => tools.push(tool),
        onBeforeTurnStart: (hook) => beforeTurnStart.push(hook),
        onBeforeTurnEnd: (hook) => beforeTurnEnd.push(hook),
      });
      return { tools, beforeTurnStart, beforeTurnEnd };
    }
  };
}

import { definePlugin } from "../plugin-sdk";

/**
 * Example user plugin. In production this would live in its own folder with a
 * package.json (and could pull npm deps), then be pre-bundled. It exposes one
 * tool and both turn-lifecycle hooks.
 */
export default definePlugin((host) => {
  host.addTool({
    name: "shout",
    run: (text) => String(text).toUpperCase(),
  });

  host.onBeforeTurnStart((ctx) => {
    return `echo-plugin: turn #${ctx.turn} starting (input="${ctx.input}")`;
  });

  host.onBeforeTurnEnd((ctx) => {
    return `echo-plugin: turn #${ctx.turn} ending`;
  });
});

/**
 * Pre-bundle step: compile + bundle each plugin's TypeScript into a single ESM
 * string that the Worker Loader can run at runtime (no build step exists inside
 * workerd). `cloudflare:workers` is kept external — the runtime provides it.
 *
 * Run with: bun run build:plugins
 */
const PLUGINS = [
  { entry: "src/plugins/echo-plugin.ts", out: "src/plugins/echo-plugin.bundle.ts", constName: "ECHO_PLUGIN_BUNDLE" },
];

for (const plugin of PLUGINS) {
  const result = await Bun.build({
    entrypoints: [plugin.entry],
    target: "browser",
    format: "esm",
    external: ["cloudflare:workers"],
  });

  if (!result.success) {
    console.error(result.logs);
    process.exit(1);
  }

  const code = await result.outputs[0]!.text();
  const file = `// GENERATED by scripts/build-plugins.ts — do not edit by hand.\nexport const ${plugin.constName} = ${JSON.stringify(code)};\n`;
  await Bun.write(plugin.out, file);
  console.log(`bundled ${plugin.entry} -> ${plugin.out} (${code.length} bytes)`);
}

import { DurableObject } from "cloudflare:workers";
import type { Env } from "./env";
import { ECHO_PLUGIN_BUNDLE } from "./plugins/echo-plugin.bundle";
import type { PluginManifest, TurnContext } from "./plugin-sdk";

// Shape of the plugin's default export once loaded as a dynamic Worker.
interface PluginEntrypoint {
  register(): Promise<PluginManifest>;
}

/**
 * Loads a pre-bundled plugin via the Worker Loader, collects its manifest
 * (tools + lifecycle hooks), and runs a mock agent turn that invokes the
 * before/after hooks and a tool. Plugin code is sandboxed in its own isolate.
 */
export class PluginHost extends DurableObject<Env> {
  async runDemoTurn(input: string): Promise<string> {
    // JIT-load the pre-bundled plugin (kept warm by id).
    const worker = this.env.LOADER.get("echo-plugin@1", async () => ({
      compatibilityDate: "2026-06-25",
      mainModule: "plugin.js",
      modules: { "plugin.js": ECHO_PLUGIN_BUNDLE },
      globalOutbound: null, // sandbox: no network for this plugin
    }));

    const plugin = worker.getEntrypoint() as unknown as PluginEntrypoint;
    const manifest = await plugin.register();

    const turn = ((await this.ctx.storage.get<number>("turn")) ?? 0) + 1;
    await this.ctx.storage.put("turn", turn);
    const ctx: TurnContext = { turn, input };

    const log: string[] = [`--- agent turn #${turn} (input="${input}") ---`];

    // 1) fire beforeTurnStart hooks (each call is RPC back into the plugin)
    for (const hook of manifest.beforeTurnStart) {
      log.push(`beforeTurnStart -> ${await hook(ctx)}`);
    }

    // 2) mock "model" step: invoke a registered tool
    const tool = manifest.tools.find((t) => t.name === "shout");
    if (tool) {
      log.push(`tool "${tool.name}"("${input}") -> ${await tool.run(input)}`);
    }

    // 3) fire beforeTurnEnd hooks
    for (const hook of manifest.beforeTurnEnd) {
      log.push(`beforeTurnEnd -> ${await hook(ctx)}`);
    }

    return `${log.join("\n")}\n`;
  }
}

import type { AppRunner } from "./supervisor";
import type { MyDurableObject } from "./counter";
import type { PluginHost } from "./plugin-host";

export interface Env {
  MY_DURABLE_OBJECT: DurableObjectNamespace<MyDurableObject>;
  APP_RUNNER: DurableObjectNamespace<AppRunner>;
  PLUGIN_HOST: DurableObjectNamespace<PluginHost>;
  LOADER: WorkerLoader;
}

